outputs.main.sas:
*-----------------------------------------------------------------------------*
| Program Name    : suppdm.sas                                               |
| Purpose         : Create SDTM SUPPDM (Supplemental DM) domain              |
| Input           : Raw supplemental DM data                                 |
| Output          : SUPPDM.sas7bdat, suppdm.xpt                             |
| Programmer      : [Programmer Name]                                        |
| Date Created    : [Date]                                                   |
*-----------------------------------------------------------------------------*;

%let studyid = CLINPROG;

libname rawdata "path/to/rawdata";
libname sdtm "path/to/sdtm";

*-----------------------------------------------------------------------------*
* Read raw supplemental DM data                                              *
*-----------------------------------------------------------------------------*;

data suppdm_raw;
    set rawdata.suppdm_raw;
run;

*-----------------------------------------------------------------------------*
* Create SUPPDM domain                                                       *
*-----------------------------------------------------------------------------*;

data suppdm;
    length STUDYID $20 RDOMAIN $2 USUBJID $40 IDVAR $8 IDVARVAL $200 
           QNAM $8 QLABEL $40 QVAL $200;

    set suppdm_raw;

    * Set STUDYID *;
    STUDYID = "&studyid";

    * Set RDOMAIN *;
    RDOMAIN = "DM";

    * Derive USUBJID *;
    if not missing(SITEID) and not missing(SUBJID) then
        USUBJID = strip(STUDYID) || "-" || strip(SITEID) || "-" || strip(SUBJID);
    else if not missing(SUBJID) then
        USUBJID = strip(STUDYID) || "-" || strip(SUBJID);

    * Set IDVAR and IDVARVAL *;
    IDVAR = "USUBJID";
    IDVARVAL = strip(USUBJID);

    * Keep only necessary variables for output *;
    keep STUDYID RDOMAIN USUBJID IDVAR IDVARVAL QNAM QLABEL QVAL;
run;

*-----------------------------------------------------------------------------*
* Sort by USUBJID and QNAM for SUPPDMSEQ derivation                         *
*-----------------------------------------------------------------------------*;

proc sort data=suppdm;
    by USUBJID QNAM;
run;

*-----------------------------------------------------------------------------*
* Derive SUPPDMSEQ (sequential numbering per subject)                       *
*-----------------------------------------------------------------------------*;

data suppdm;
    set suppdm;
    by USUBJID;

    retain SUPPDMSEQ;

    if first.USUBJID then SUPPDMSEQ = 1;
    else SUPPDMSEQ + 1;
run;

*-----------------------------------------------------------------------------*
* Apply variable attributes per SDTM specification                          *
*-----------------------------------------------------------------------------*;

data suppdm;
    attrib
        STUDYID   length=$20  label="Study Identifier"
        RDOMAIN   length=$2   label="Related Domain Abbreviation"
        USUBJID   length=$40  label="Unique Subject Identifier"
        IDVAR     length=$8   label="Identifying Variable"
        IDVARVAL  length=$200 label="Identifying Variable Value"
        QNAM      length=$8   label="Qualifier Variable Name"
        QLABEL    length=$40  label="Qualifier Variable Label"
        QVAL      length=$200 label="Data Value"
        SUPPDMSEQ length=8    label="Sequence Number"
    ;

    set suppdm;

    * Ensure proper variable order *;
    keep STUDYID RDOMAIN USUBJID IDVAR IDVARVAL QNAM QLABEL QVAL SUPPDMSEQ;
run;

*-----------------------------------------------------------------------------*
* Final sort by STUDYID, USUBJID, SUPPDMSEQ                                 *
*-----------------------------------------------------------------------------*;

proc sort data=suppdm;
    by STUDYID USUBJID SUPPDMSEQ;
run;

*-----------------------------------------------------------------------------*
* Create permanent SAS dataset                                               *
*-----------------------------------------------------------------------------*;

data sdtm.suppdm;
    set suppdm;
run;

*-----------------------------------------------------------------------------*
* Create XPT transport file                                                  *
*-----------------------------------------------------------------------------*;

libname xptout xport "path/to/sdtm/suppdm.xpt";

data xptout.suppdm;
    set sdtm.suppdm;
run;

libname xptout clear;

*-----------------------------------------------------------------------------*
* Print summary statistics                                                   *
*-----------------------------------------------------------------------------*;

proc contents data=sdtm.suppdm varnum;
run;

proc freq data=sdtm.suppdm;
    tables QNAM / nocum;
run;

proc sql;
    select count(*) as Total_Records,
           count(distinct USUBJID) as Total_Subjects
    from sdtm.suppdm;
quit;
